$items = @scandir($root);
if($items){
    $dirs = $files = array();
    foreach($items as $item){
        if($item==='.'||$item==='..')continue;
        $full = $root.'/'.$item;
        if(is_dir($full)) $dirs[] = $item; else $files[] = $item;
    }
    sort($dirs); sort($files);
    foreach($dirs as $d){
        $full = $root.'/'.$d;
        $mod = date('Y-m-d H:i', filemtime($full));
        echo '<tr><td class="dir"><a href="?dir='.base64_encode($full).'">'
            .htmlspecialchars($d).'</a></td>'
            .'<td class="sz">&mdash;</td><td>'.$mod.'</td>'
            .'<td class="acts"><a href="?dir='.base64_encode($root).'&a=delete&target='.base64_encode($full).'" class="del" onclick="return confirm(\'Delete folder '.htmlspecialchars(addslashes($d)).' and all contents?\')">delete</a></td></tr>';
    }
    foreach($files as $f){
        $full = $root.'/'.$f;
        $sz = filesize($full);
        $szh = $sz>1048576?round($sz/1048576,1).'M':($sz>1024?round($sz/1024,1).'K':$sz.'B');
        $mod = date('Y-m-d H:i', filemtime($full));
        $b64full = base64_encode($full);
        echo '<tr><td><a href="#" onclick="viewFile(\''.$b64full.'\',\''.$b64full.'\');return false">'
            .htmlspecialchars($f).'</a></td>'
            .'<td class="sz">'.$szh.'</td><td>'.$mod.'</td>'
            .'<td class="acts"><a href="?dir='.base64_encode($root).'&a=edit&file='.$b64full.'">edit</a>'
            .'<a href="?dir='.base64_encode($root).'&a=delete&target='.$b64full.'" class="del" onclick="return confirm(\'Delete '.htmlspecialchars(addslashes($f)).'?\')">del</a></td></tr>';
    }
}
