<script>
function b64d(s){try{return decodeURIComponent(escape(atob(s)));}catch(e){return atob(s);}}
function viewFile(fileB64,editB64){
    var x=new XMLHttpRequest();
    x.open('GET','?a=view&file='+encodeURIComponent(fileB64),true);
    x.onreadystatechange=function(){
        if(x.readyState===4&&x.status===200){
            try{
                var r=JSON.parse(x.responseText);
                var content=b64d(r.c);
                var fname=b64d(r.f);
                document.getElementById('viewer-fname').textContent=fname;
                var codeEl=document.getElementById('viewer-code');
                codeEl.textContent=content;
                codeEl.className='';
                var ext=fname.split('.').pop().toLowerCase();
                var langMap={'php':'php','js':'javascript','py':'python','rb':'ruby','css':'css','html':'xml','htm':'xml','xml':'xml','json':'json','sql':'sql','sh':'bash','bash':'bash','yml':'yaml','yaml':'yaml','md':'markdown','ts':'typescript','java':'java','c':'c','cpp':'cpp','h':'c','go':'go','rs':'rust','conf':'ini','ini':'ini','txt':'plaintext','log':'plaintext'};
                if(langMap[ext])codeEl.className='language-'+langMap[ext];
                hljs.highlightElement(codeEl);
                document.getElementById('viewer-edit-btn').href='?a=edit&dir='+encodeURIComponent('<?=base64_encode($root)?>')+'&file='+encodeURIComponent(editB64);
                document.getElementById('viewer-overlay').classList.add('active');
            }catch(e){console.error(e);}
        }
    };
    x.send();
}
function closeViewer(){document.getElementById('viewer-overlay').classList.remove('active');}
document.addEventListener('keydown',function(e){if(e.key==='Escape')closeViewer();});

</script>
